addresses = {}

@app.route('/address', methods=['POST'])
def save_address():
    user_id = request.form.get('user_id')
    if user_id in addresses:
        return {'error': 'Address already exists'}, 400
    addresses[user_id] = request.form.get('address')
    return {'message': 'Address saved successfully'}, 200

@app.route('/address', methods=['GET'])
def get_address():
    user_id = request.args.get('user_id')
    if user_id not in addresses:
        return {'error': 'Address does not exist'}, 400
    return {'address': addresses[user_id]}, 200

